const items = [];

for (const item of $input.all()) {

    const transcript = item.json.transcript;
    const filename = item.json.fileName;

    let account_id;

    if (filename) {
        account_id = filename.replace(".txt","");
    } else {
        account_id = "account_" + Date.now();
    }

    items.push({
        json: {
            account_id: account_id,
            transcript: transcript
        }
    });
}

return items;

let transcript = $json.transcript || "";

// clean problematic characters
transcript = transcript
  .replace(/\r/g, " ")
  .replace(/\n/g, " ")
  .replace(/"/g, '\\"');

// limit size to avoid Groq token limit
if (transcript.length > 4000) {
  transcript = transcript.substring(0, 4000);
}

return [
  {
    json: {
      account_id: $json.account_id,
      transcript_clean: transcript
    }
  }
];

const raw = $json.choices[0].message.content;

// remove markdown code blocks
const cleaned = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

// parse JSON
const parsed = JSON.parse(cleaned);

return [
  {
    json: parsed
  }
];
